import time

class Solution:
  def threeSum(self, nums: list[int]) -> list[list[int]]:
    output = []
    nums.sort()

    for i, a in enumerate(nums):
      if a > 0:
        break

      if i > 0 and a == nums[i-1]:
        continue

      l, r = i+1, len(nums) - 1
      while r > l:
        p_sum = a + nums[l] + nums[r]
        if p_sum > 0:
          r -= 1
        elif p_sum < 0:
          l += 1
        else:
          output.append([a, nums[l], nums[r]])
          l += 1
          r -= 1

          while nums[l] == nums[l - 1] and l < r:
            l += 1
      
    return output
  
